VALUES
  ('disabled-6f0ba476-moex-00621', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '在有x與y兩種財貨的哈柏格（Harberger）模型中，x為資本相對密集產業， 若對x部門所使用之資本課稅，下列敘述何者錯誤？', '["課稅使x財貨的相對價格提高", "產出效果使資本的相對淨報酬提高", "要素替代效果使資本的相對淨報酬下降", "資本比勞動負擔相對多的稅負"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00622', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '在一完全競爭市場中，需求函數為 P＝200－2Q，供給函數為 Q＝50，其中 P是價格，Q為數量。政府對該市場的產品課徵5元的從量貨物稅，若不考 慮其他市場，因課稅所產生的超額負擔為多少？', '["0", "16", "25", "36"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00623', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '假設一消費者有固定的所得，他消費兩個財貨，兩財貨皆在完全競爭市場生 產且邊際成本固定不變，這兩個財貨不是完全互補，若政府對其中一個財貨 課徵從價稅，下列關於課稅引起的超額負擔之敘述何者錯誤？', '["兩財貨間的替代效果愈大，則超額負擔愈大", "稅率為原來的2倍，其他條件不變，則超額負擔為原來的4倍", "被課稅財貨的受補償需求彈性絕對值愈大，則超額負擔愈大", "若消費者原先花在課稅財貨的支出愈大，則超額負擔愈小"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00624', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '經濟學家認為課徵矯正污染之皮古稅（Pigoviantaxes）會產生雙重紅利，雙 重紅利是指：', '["可以減少水污染也可以減少空氣污染", "可以減少污染也可以幫助經濟成長", "可以減少污染也可以讓防治污染廠商賺到利潤", "可以減少污染也可以讓政府減少其他扭曲性租稅並降低超額負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00625', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '有一線性所得稅函數如下：稅額＝t×所得－E，其中t為邊際稅率，E為一正 整數。下列敘述何者正確？', '["此線性所得稅不會產生超額負擔", "平均稅率隨所得增加而增加", "E的大小與平均稅率無關", "我國現行綜合所得稅屬線性所得稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00626', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '關於反彈性法則（inverseelasticityrule）之敘述，下列何者錯誤？', '["須假設財貨間無互補替代關係", "為雷姆西（Ramsey）法則之特例", "須滿足租稅中立性", "為次佳理論之應用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00627', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '關於課稅原則之敘述，下列何者正確？', '["我國現行所得稅符合課稅的利益原則（benefitprinciple）", "我國現行營業稅符合課稅的利益原則", "所得稅列舉扣除項目愈多愈符合水平公平原則", "累進所得稅符合垂直公平原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00628', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '假設休閒為正常財，若政府對代表性勞動供給者之勞動所得課稅，對其休閒 及工作時數產生何種變化？', '["所得效果不影響休閒及工作時數", "替代效果使休閒減少，工作時數增加", "所得效果使休閒減少，工作時數增加", "所得效果使休閒增加，工作時數減少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00629', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '甲在年初有市價100萬元的股票，年底市價為180萬元，除此以外沒有其他 資產，甲當年度的消費支出為100萬元。依據Haig-Simons之定義，甲當年 度所得為多少？', '["130萬元", "150萬元", "180萬元", "200萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00630', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '採夫妻各類所得分開計稅方式合併申報綜合所得稅之相關規定，下列敘述何 者正確？', '["適用於受扶養之子女的特別扣除額不得由分開計稅者扣除", "分開計稅者得扣除其房貸利息支出", "允許夫妻各類所得分開計稅之目的為簡化申報程序，降低納稅者之遵從成 本（compliancecost）", "儲蓄投資特別扣除額不得由分開計稅者扣除"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:32+00:00", "source_pdf_sha1": "1c20aeb7394a", "answer_pdf_sha1": "470263c0141a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
